code:
- uses: actions/create-release@v1
  env:
    GITHUB_TOKEN: ${{ secrets.GITHUB_TOKEN }}
  with:
    tag_name: ${{ github.ref }}
    release_name: Release ${{ github.ref }}

concurrency:
  group: ${{ github.workflow }}-${{ github.ref }}
  cancel-in-progress: true

- name: Send Telegram Message
  uses: appleboy/telegram-action@master
  with:
    to: ${{ secrets.TELEGRAM_TO }}
    token: ${{ secrets.TELEGRAM_TOKEN }}
    message: | 
      Ⲙ𝔬ⲃⳝ𝔭 構建狀態：${{ job.status }}
      提交人：${{ github.actor }}
      更新內容：${{ github.event.head_commit.message }}

- uses: 8398a7/action-slack@v3
  with:
    status: ${{ job.status }}
  env:
    SLACK_WEBHOOK_URL: ${{ secrets.SLACK_WEBHOOK }}

env:
  ROLE: ${{ github.actor == 'admin' && 'SUPERUSER' || 'DEVELOPER' }}
- run: echo "Current Role is $ROLE"

- name: Purge Cache
  uses: jakejarvis/cloudflare-purge-action@master
  env:
    CLOUDFLARE_ZONE: ${{ secrets.CF_ZONE }}
    CLOUDFLARE_TOKEN: ${{ secrets.CF_TOKEN }}

- name: Error Handler
  if: failure()
  run: cat error.log | pbcopy # 或推送到 webhook

self.addEventListener('fetch', e => {
  e.respondWith(caches.match(e.request).then(res => res || fetch(e.request)));
});

